import { Request, Response, NextFunction } from 'express';
import { securityLogger } from '../services/securityLogger';
import { isIPWhitelisted } from './rateLimiter';

interface DDosMetrics {
  requestCount: number;
  firstRequest: number;
  lastRequest: number;
  userAgent: string;
  endpoints: Set<string>;
  suspiciousPatterns: string[];
}

// In-memory DDoS tracking
const ddosTracker = new Map<string, DDosMetrics>();
const DDOS_THRESHOLDS = {
  REQUESTS_PER_MINUTE: 30,
  REQUESTS_PER_HOUR: 200,
  UNIQUE_ENDPOINTS_THRESHOLD: 15,
  SUSPICIOUS_SCORE_THRESHOLD: 5
};

// Clean up old entries every 5 minutes
setInterval(() => {
  const now = Date.now();
  const oneHour = 60 * 60 * 1000;

  ddosTracker.forEach((metrics, ip) => {
    if (now - metrics.firstRequest > oneHour) {
      ddosTracker.delete(ip);
    }
  });
}, 5 * 60 * 1000);

export function ddosProtectionMiddleware(req: Request, res: Response, next: NextFunction) {
  const ip = req.ip || req.connection.remoteAddress || 'unknown';
  const userAgent = req.headers['user-agent'] || '';
  const endpoint = req.url;
  const now = Date.now();

  // Skip DDoS protection for whitelisted IPs
  if (isIPWhitelisted(ip)) {
    return next();
  }

  // Initialize or update metrics for this IP
  if (!ddosTracker.has(ip)) {
    ddosTracker.set(ip, {
      requestCount: 1,
      firstRequest: now,
      lastRequest: now,
      userAgent,
      endpoints: new Set([endpoint]),
      suspiciousPatterns: []
    });
    return next();
  }

  const metrics = ddosTracker.get(ip)!;
  metrics.requestCount++;
  metrics.lastRequest = now;
  metrics.endpoints.add(endpoint);

  // Check for DDoS patterns
  const timeWindow = now - metrics.firstRequest;
  const requestsPerMinute = (metrics.requestCount / (timeWindow / 60000));
  const requestsPerHour = (metrics.requestCount / (timeWindow / 3600000));

  // Detect suspicious patterns
  const suspiciousPatterns: string[] = [];

  // Pattern 1: Too many requests per minute
  if (requestsPerMinute > DDOS_THRESHOLDS.REQUESTS_PER_MINUTE) {
    suspiciousPatterns.push(`High request rate: ${requestsPerMinute.toFixed(1)}/min`);
  }

  // Pattern 2: Too many unique endpoints accessed
  if (metrics.endpoints.size > DDOS_THRESHOLDS.UNIQUE_ENDPOINTS_THRESHOLD) {
    suspiciousPatterns.push(`Endpoint scanning: ${metrics.endpoints.size} unique endpoints`);
  }

  // Pattern 3: Changing user agents (bot rotation)
  if (userAgent !== metrics.userAgent && metrics.userAgent) {
    suspiciousPatterns.push('User agent rotation detected');
    metrics.userAgent = userAgent;
  }

  // Pattern 4: Rapid consecutive requests
  if (metrics.requestCount > 1) {
    const timeSinceLastRequest = now - metrics.lastRequest;
    if (timeSinceLastRequest < 100) { // Less than 100ms between requests
      suspiciousPatterns.push('Rapid fire requests detected');
    }
  }

  // Update suspicious patterns
  metrics.suspiciousPatterns = [...new Set([...metrics.suspiciousPatterns, ...suspiciousPatterns])];

  // Calculate threat level
  const threatLevel = calculateThreatLevel(metrics, requestsPerMinute, requestsPerHour);

  // Take action based on threat level
  if (threatLevel >= DDOS_THRESHOLDS.SUSPICIOUS_SCORE_THRESHOLD) {
    securityLogger.log({
      type: 'suspicious_activity',
      ip,
      details: `DDoS attack detected. Threat level: ${threatLevel}/10. Patterns: ${metrics.suspiciousPatterns.join(', ')}`,
      url: req.url,
      userAgent,
      metadata: {
        requestCount: metrics.requestCount,
        requestsPerMinute: requestsPerMinute.toFixed(1),
        uniqueEndpoints: metrics.endpoints.size,
        timeWindow: Math.round(timeWindow / 1000) + 's'
      }
    });

    return res.status(429).json({
      error: '🛡️ DDoS protection activated. Your IP has been temporarily blocked due to suspicious activity patterns.',
      code: 'DDOS_PROTECTION',
      retryAfter: 300, // 5 minutes
      details: 'If you believe this is an error, please wait a few minutes and try again with normal browsing behavior.'
    });
  }

  // Log high activity for monitoring
  if (threatLevel >= 3) {
    console.log(`🔍 High activity from ${ip}: threat level ${threatLevel}, ${requestsPerMinute.toFixed(1)} req/min`);
  }

  next();
}

function calculateThreatLevel(metrics: DDosMetrics, requestsPerMinute: number, requestsPerHour: number): number {
  let score = 0;

  // Request rate scoring
  if (requestsPerMinute > 50) score += 4;
  else if (requestsPerMinute > 30) score += 3;
  else if (requestsPerMinute > 15) score += 2;
  else if (requestsPerMinute > 10) score += 1;

  // Endpoint diversity scoring
  if (metrics.endpoints.size > 20) score += 3;
  else if (metrics.endpoints.size > 15) score += 2;
  else if (metrics.endpoints.size > 10) score += 1;

  // Suspicious pattern scoring
  score += Math.min(metrics.suspiciousPatterns.length, 3);

  return Math.min(score, 10); // Cap at 10
}

// Endpoint to check DDoS protection status (for monitoring)
export function getDDoSStatus() {
  const now = Date.now();
  const activeThreats: any[] = [];
  ddosTracker.forEach((metrics, ip) => {
    const requestsPerMinute = metrics.requestCount / ((now - metrics.firstRequest) / 60000);
    if (requestsPerMinute > 10 || metrics.suspiciousPatterns.length > 0) {
      activeThreats.push({
        ip: ip.replace(/\d{1,3}$/, 'xxx'), // Mask last octet for privacy
        requestCount: metrics.requestCount,
        requestsPerMinute: requestsPerMinute.toFixed(1),
        uniqueEndpoints: metrics.endpoints.size,
        suspiciousPatterns: metrics.suspiciousPatterns.length,
        threatLevel: calculateThreatLevel(metrics, requestsPerMinute, 
          metrics.requestCount / ((now - metrics.firstRequest) / 3600000))
      });
    }
  });

  return {
    activeConnections: ddosTracker.size,
    activeThreats: activeThreats.length,
    threats: activeThreats.slice(0, 10), // Only show top 10 threats
    timestamp: new Date().toISOString()
  };
}

server/middleware/rateLimiter.ts.content:
import { Request, Response, NextFunction } from 'express';
import { securityLogger } from '../services/securityLogger';

interface RateLimitStore {
  [ip: string]: {
    count: number;
    firstRequest: number;
    lastRequest: number;
  };
}

// In-memory store for rate limiting (consider Redis for production)
const rateLimitStore: RateLimitStore = {};
const dailyStore: RateLimitStore = {};

// Clean up old entries every hour
setInterval(() => {
  const now = Date.now();
  const oneHour = 60 * 60 * 1000;
  const oneDay = 24 * 60 * 60 * 1000;

  // Clean hourly store
  for (const ip in rateLimitStore) {
    if (now - rateLimitStore[ip].firstRequest > oneHour) {
      delete rateLimitStore[ip];
    }
  }

  // Clean daily store
  for (const ip in dailyStore) {
    if (now - dailyStore[ip].firstRequest > oneDay) {
      delete dailyStore[ip];
    }
  }
}, 60 * 60 * 1000); // Run every hour

// Whitelist for development testing and user's devices
const WHITELISTED_IPS = [
  '127.0.0.1',
  'localhost',
  '::1',
  '::ffff:127.0.0.1',
  '172.31.76.98', // Development IP
  '172.31.93.34', // Development IP
  '172.31.118.66', // Development IP
  '35.185.93.79', // User's external IP (phone/laptop)
  '34.73.234.246', // User's current IP
];

// Whitelisted emails (user's email exempt from email limits)
const WHITELISTED_EMAILS = [
  'avoidaccess@msn.com', // User's email - unlimited pins
];

export function createRateLimiter(options: {
  windowMs: number;
  maxRequests: number;
  message: string;
  skipSuccessfulRequests?: boolean;
}) {
  return (req: Request, res: Response, next: NextFunction) => {
    // Get real IP address (considering proxies)
    const ip = req.ip || 
               req.connection.remoteAddress || 
               req.socket.remoteAddress ||
               (req.headers['x-forwarded-for'] as string)?.split(',')[0]?.trim() ||
               'unknown';

    // Skip rate limiting for whitelisted IPs (development only)
    if (process.env.NODE_ENV === 'development' && WHITELISTED_IPS.includes(ip)) {
      console.log(`🔓 Skipping rate limit for whitelisted IP: ${ip}`);
      return next();
    }

    // Also skip if IP starts with development patterns
    if (process.env.NODE_ENV === 'development' && (ip.startsWith('127.') || ip.startsWith('::') || ip.startsWith('172.'))) {
      console.log(`🔓 Skipping rate limit for development IP: ${ip}`);
      return next();
    }

    // CRITICAL FIX: Allow ALL localhost requests in production for CI/CD
    // This is needed for Docker container health checks and deployment verification
    if (process.env.NODE_ENV === 'production' && 
        (ip === '127.0.0.1' || ip === 'localhost' || ip === '::1' || ip === '::ffff:127.0.0.1')) {
      console.log(`🔓 Allowing localhost request in production: ${ip} for ${req.path}`);
      return next();
    }

    const now = Date.now();
    const store = options.windowMs > 3600000 ? dailyStore : rateLimitStore;

    if (!store[ip]) {
      store[ip] = {
        count: 1,
        firstRequest: now,
        lastRequest: now
      };
      return next();
    }

    const timeWindow = now - store[ip].firstRequest;

    // Reset if outside time window
    if (timeWindow > options.windowMs) {
      store[ip] = {
        count: 1,
        firstRequest: now,
        lastRequest: now
      };
      return next();
    }

    // Check if limit exceeded
    if (store[ip].count >= options.maxRequests) {
      securityLogger.log({
        type: 'rate_limit',
        ip,
        details: `Rate limit exceeded: ${store[ip].count}/${options.maxRequests} requests in ${Math.ceil(timeWindow / 1000)}s`,
        url: req.url,
        userAgent: req.headers['user-agent'] as string
      });

      return res.status(429).json({
        error: options.message,
        retryAfter: Math.ceil((options.windowMs - timeWindow) / 1000),
        limit: options.maxRequests,
        remaining: 0
      });
    }

    // Increment counter
    store[ip].count++;
    store[ip].lastRequest = now;

    // Add rate limit headers
    res.set({
      'X-RateLimit-Limit': options.maxRequests.toString(),
      'X-RateLimit-Remaining': (options.maxRequests - store[ip].count).toString(),
      'X-RateLimit-Reset': new Date(store[ip].firstRequest + options.windowMs).toISOString()
    });

    next();
  };
}

// Enhanced anti-bot detection middleware with friendly messages
export function antibotMiddleware(req: Request, res: Response, next: NextFunction) {
  const userAgent = req.headers['user-agent'] || '';
  const ip = req.ip || req.connection.remoteAddress || 'unknown';

  // Skip anti-bot for whitelisted IPs
  if (isIPWhitelisted(ip)) {
    return next();
  }

  // CRITICAL FIX: Allow localhost requests in production for CI/CD health checks
  // This prevents blocking curl/wget from localhost during deployment verification
  if (process.env.NODE_ENV === 'production' && 
      (ip === '127.0.0.1' || ip === 'localhost' || ip === '::1' || ip === '::ffff:127.0.0.1')) {
    console.log(`🔓 Allowing localhost request in production for CI/CD: ${ip}`);
    return next();
  }

  // Block requests without user agent (likely bots)
  if (!userAgent) {
    securityLogger.log({
      type: 'bot_detected',
      ip,
      details: 'No user agent provided',
      url: req.url
    });
    return res.status(403).json({ 
      error: '🤖 Missing browser information. Please use a standard web browser to access addypin.',
      code: 'NO_USER_AGENT'
    });
  }

  // Block known bot patterns with friendly messages
  const botPatterns = [
    { pattern: /bot/i, message: 'Automated bot detected' },
    { pattern: /crawl/i, message: 'Web crawler detected' },
    { pattern: /spider/i, message: 'Web spider detected' },
    { pattern: /scrape/i, message: 'Web scraper detected' },
    { pattern: /curl/i, message: 'Command line tool detected' },
    { pattern: /wget/i, message: 'Download tool detected' },
    { pattern: /python/i, message: 'Python script detected' },
    { pattern: /postman/i, message: 'API testing tool detected' },
    { pattern: /headless/i, message: 'Headless browser detected' },
    { pattern: /phantom/i, message: 'Automated browser detected' }
  ];

  const detectedBot = botPatterns.find(bot => bot.pattern.test(userAgent));
  if (detectedBot) {
    securityLogger.log({
      type: 'bot_detected',
      ip,
      details: `${detectedBot.message}: ${userAgent}`,
      url: req.url,
      userAgent
    });
    return res.status(403).json({ 
      error: `🤖 ${detectedBot.message}. addypin is designed for human users. Please use a standard web browser.`,
      code: 'BOT_DETECTED'
    });
  }

  // Advanced suspicious activity detection
  const suspiciousIndicators = {
    noReferer: !req.headers.referer && req.method === 'POST',
    unusualContentType: req.headers['content-type'] && !req.headers['content-type'].includes('application/json'),
    rapidRequests: checkRapidRequests(ip),
    suspiciousHeaders: countSuspiciousHeaders(req)
  };

  let suspicionScore = 0;
  if (suspiciousIndicators.noReferer) suspicionScore += 2;
  if (suspiciousIndicators.unusualContentType) suspicionScore += 1;
  if (suspiciousIndicators.rapidRequests) suspicionScore += 3;
  if (suspiciousIndicators.suspiciousHeaders > 2) suspicionScore += 2;

  // High suspicion - apply strict rate limiting
  if (suspicionScore >= 4) {
    securityLogger.log({
      type: 'suspicious_activity',
      ip,
      details: `High suspicion score: ${suspicionScore}. Indicators: ${JSON.stringify(suspiciousIndicators)}`,
      url: req.url,
      userAgent
    });
    // Apply stricter rate limiting for suspicious users
    return strictBotLimiter(req, res, next);
  }

  // Medium suspicion - log but allow
  if (suspicionScore >= 2) {
    console.log(`⚠️ Moderate suspicious activity from ${ip}: score ${suspicionScore}`);
  }

  next();
}

// Helper function to detect rapid requests from same IP
const rapidRequestTracker = new Map<string, number[]>();
function checkRapidRequests(ip: string): boolean {
  const now = Date.now();
  if (!rapidRequestTracker.has(ip)) {
    rapidRequestTracker.set(ip, [now]);
    return false;
  }

  const requests = rapidRequestTracker.get(ip)!;
  // Remove requests older than 1 minute
  const recentRequests = requests.filter(time => now - time < 60000);
  recentRequests.push(now);
  rapidRequestTracker.set(ip, recentRequests);

  // More than 10 requests in 1 minute is suspicious
  return recentRequests.length > 10;
}

// Helper function to count suspicious headers
function countSuspiciousHeaders(req: Request): number {
  const suspiciousHeaders = [
    'x-requested-with',
    'x-forwarded-for',
    'x-real-ip',
    'x-cluster-client-ip',
    'x-forwarded',
    'forwarded-for',
    'forwarded'
  ];

  return suspiciousHeaders.filter(header => req.headers[header]).length;
}

// Enhanced DDoS protection with friendly messages
export const pinCreationLimiter = createRateLimiter({
  windowMs: 60 * 60 * 1000, // 1 hour
  maxRequests: process.env.NODE_ENV === 'development' ? 50 : 5, // 50 pins per hour in dev, 5 in prod
  message: '🚀 Wow, you\'re on fire with creating addypins! Please take a quick break (60 minutes) to prevent spam. Thanks for using addypin responsibly!'
});

export const dailyPinLimiter = createRateLimiter({
  windowMs: 24 * 60 * 60 * 1000, // 24 hours
  maxRequests: process.env.NODE_ENV === 'development' ? 200 : 5, // 200 pins per day in dev, 5 in prod (strict for production)
  message: '📍 You\'ve reached your daily limit of 5 addypins per day from this location. This helps us prevent spam and keep addypin fast for everyone! Try again tomorrow.'
});

export const generalLimiter = createRateLimiter({
  windowMs: 15 * 60 * 1000, // 15 minutes
  maxRequests: process.env.NODE_ENV === 'development' ? 1000 : 100, // Higher limits in dev
  message: '⚡ You\'re browsing addypin quite enthusiastically! Please slow down a bit to help us maintain performance for all users.'
});

// New strict bot protection limiter
export const strictBotLimiter = createRateLimiter({
  windowMs: 5 * 60 * 1000, // 5 minutes
  maxRequests: 20, // Only 20 requests per 5 minutes for suspicious patterns
  message: '🤖 Automated activity detected. If you\'re a real user, please wait a few minutes and try again.'
});

// Helper function to check if email is whitelisted
export function isEmailWhitelisted(email: string): boolean {
  return WHITELISTED_EMAILS.includes(email);
}

// Helper function to check if IP is whitelisted
export function isIPWhitelisted(ip: string): boolean {
  return WHITELISTED_IPS.includes(ip) || 
         (process.env.NODE_ENV === 'development' && 
          (ip.startsWith('127.') || ip.startsWith('::') || ip.startsWith('172.')));
}

