import { useState, useEffect } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "@/components/ui/alert-dialog";
import { useToast } from "@/hooks/use-toast";
import { MapPin, Edit, Mail, KeyRound, LogOut, Trash2 } from "lucide-react";
import type { Pin } from "@shared/schema";
import { getCountryFromCoords } from "@shared/utils";

interface UserPinsListProps {
  onPinSelect?: (pin: Pin) => void;
  onStartEditing?: () => void;
  onAuthChange?: (email: string, otpCode: string, isAuthenticated: boolean) => void;
}

export function UserPinsList({ onPinSelect, onStartEditing, onAuthChange }: UserPinsListProps) {
  const [email, setEmail] = useState("");
  const [otpCode, setOtpCode] = useState("");
  const [showOtpInput, setShowOtpInput] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [selectedPin, setSelectedPin] = useState<Pin | null>(null);
  const [editToken, setEditToken] = useState("");
  const [showDeleteConfirm, setShowDeleteConfirm] = useState<string | null>(null);
  const { toast } = useToast();

  // Fetch user pins after authentication
  const { data: userPins, refetch: refetchPins, isLoading: pinsLoading } = useQuery({
    queryKey: ['user-pins', email],
    queryFn: async () => {
      const response = await apiRequest("GET", `/api/user/pins/${encodeURIComponent(email)}`, undefined);
      return response.json();
    },
    enabled: isAuthenticated && !!email,
  });

  // Listen for pin updates to refresh the list
  useEffect(() => {
    const handlePinUpdate = () => {
      if (isAuthenticated && email) {
        refetchPins();
      }
    };

    const handlePinCreated = (event: any) => {
      if (isAuthenticated && email && event.detail?.createdBy === email) {
        refetchPins();
      }
    };

    window.addEventListener('pinUpdated', handlePinUpdate);
    window.addEventListener('pinCreated', handlePinCreated as EventListener);
    return () => {
      window.removeEventListener('pinUpdated', handlePinUpdate);
      window.removeEventListener('pinCreated', handlePinCreated as EventListener);
    };
  }, [isAuthenticated, email, refetchPins]);

  // Delete pin mutation
  const deletePinMutation = useMutation({
    mutationFn: async (shortcode: string) => {
      const response = await apiRequest("DELETE", `/api/pins/${shortcode}`, {});
      return response.json();
    },
    onSuccess: (data, shortcode) => {
      toast({
        title: "addypin deleted! 🗑️", 
        description: `addypin ${shortcode} has been permanently deleted`,
        duration: 5000,
      });
      refetchPins();
      setSelectedPin(null);
      setShowDeleteConfirm(null);
    },
    onError: (error) => {
      toast({
        title: "Delete Failed",
        description: error instanceof Error ? error.message : "Failed to delete addypin",
        variant: "destructive",
      });
    },
  });

  const sendOtpMutation = useMutation({
    mutationFn: async (email: string) => {
      const response = await apiRequest("POST", "/api/otp/send", { email });
      return response.json();
    },
    onSuccess: (data) => {
      setShowOtpInput(true);
      const otpCode = data.code;
      toast({
        title: "Code Sent! 📧",
        description: otpCode 
          ? `Development Mode: Your code is ${otpCode}`
          : "Check your email for the 6-digit verification code",
        duration: 10000,
      });
      // Log prominent instructions to help user find the OTP
      console.log(`\n🔍 ===============================`);
      console.log(`🔍 DEVELOPMENT MODE - OTP INSTRUCTIONS`);
      console.log(`🔍 Look at the Workflow Console (server logs)`);
      console.log(`🔍 Find the box with "🔑 OTP CODE FOR ${email.toUpperCase()}"`);
      console.log(`🔍 Copy the 6-digit number and paste it in the form`);
      console.log(`🔍 ===============================\n`);
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: error instanceof Error ? error.message : "Failed to send code",
        variant: "destructive",
      });
    },
  });

  const verifyOtpMutation = useMutation({
    mutationFn: async (code: string) => {
      const response = await apiRequest("POST", "/api/otp/verify", { email, code });
      return response.json();
    },
    onSuccess: (data) => {
      setEditToken(data.editToken);
      setIsAuthenticated(true);
      setShowOtpInput(false);

      // Notify parent component about authentication change
      if (onAuthChange) {
        onAuthChange(email, otpCode, true);
      }

      // Force refetch after a small delay to ensure the query is enabled
      setTimeout(() => {
        refetchPins();
      }, 100);

      toast({
        title: "Email Verified! ✅",
        description: "Loading your addypins...",
        duration: 5000,
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: error instanceof Error ? error.message : "Invalid OTP",
        variant: "destructive",
      });
    },
  });

  const handlePinSelect = (pin: Pin) => {
    setSelectedPin(pin);
    if (onPinSelect) {
      onPinSelect(pin);
    }
  };

  const handleStartEditing = () => {
    if (selectedPin && onStartEditing) {
      onStartEditing();
    }
  };

  if (!isAuthenticated) {
    return (
      <Card className="w-full">
        <CardHeader>
          <CardTitle className="flex items-center">
            <Mail className="w-5 h-5 text-addypin-cyan mr-2" />
            My addypins
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <p className="text-sm text-gray-600">
            Login to view and edit your registered addypins
          </p>

          <div>
            <Label htmlFor="user-email" className="block text-sm font-medium text-addypin-dark mb-2">
              Email address
            </Label>
            <Input
              id="user-email"
              type="email"
              placeholder="your@email.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="border-gray-300 focus:border-addypin-cyan focus:ring-addypin-cyan placeholder:text-gray-400"
              data-testid="input-user-email"
            />
          </div>

          {!showOtpInput ? (
            <Button
              onClick={() => sendOtpMutation.mutate(email)}
              disabled={!email || sendOtpMutation.isPending}
              className="w-full bg-addypin-cyan hover:bg-cyan-600 text-white"
              data-testid="button-send-user-otp"
            >
              <Mail className="w-4 h-4 mr-2" />
              {sendOtpMutation.isPending ? "Sending..." : "Send Verification Code"}
            </Button>
          ) : (
            <div className="space-y-3">
              <div>
                <Label htmlFor="user-otp" className="block text-sm font-medium text-addypin-dark mb-2">
                  Verification Code
                </Label>
                <Input
                  id="user-otp"
                  type="text"
                  placeholder="123456"
                  value={otpCode}
                  onChange={(e) => setOtpCode(e.target.value)}
                  maxLength={6}
                  className="text-center tracking-widest text-lg border-gray-300 focus:border-addypin-cyan focus:ring-addypin-cyan placeholder:text-gray-400"
                  data-testid="input-user-otp"
                />
              </div>

              <Button
                onClick={() => verifyOtpMutation.mutate(otpCode)}
                disabled={otpCode.length !== 6 || verifyOtpMutation.isPending}
                className="w-full bg-addypin-cyan hover:bg-cyan-600 text-white"
                data-testid="button-verify-user-otp"
              >
                <KeyRound className="w-4 h-4 mr-2" />
                {verifyOtpMutation.isPending ? "Verifying..." : "Verify Code"}
              </Button>
            </div>
          )}
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className="w-full">
      <CardHeader className="pb-3">
        <CardTitle className="flex items-center justify-between text-sm">
          <div className="flex items-center">
            <MapPin className="w-4 h-4 text-addypin-cyan mr-2" />
            Edit addypins ({(userPins as Pin[])?.length || 0})
          </div>
          <Button
            onClick={() => {
              setIsAuthenticated(false);
              setEmail("");
              setOtpCode("");
              setShowOtpInput(false);
              setSelectedPin(null);
              setEditToken("");
            }}
            variant="outline"
            size="sm"
            className="text-xs h-6 px-2"
          >
            <LogOut className="w-3 h-3 mr-1" />
            Log out
          </Button>
        </CardTitle>
      </CardHeader>
      <CardContent className="pt-0">
        {!userPins || (userPins as Pin[]).length === 0 ? (
          <p className="text-xs text-gray-500 text-center py-3">
            No addypins found for this email address
          </p>
        ) : (
          <div className="space-y-2 max-h-64 overflow-y-auto">
            {(userPins as Pin[]).map((pin) => (
              <div
                key={pin.id}
                className={`p-2 border rounded-lg cursor-pointer transition-all ${
                  selectedPin?.id === pin.id
                    ? 'border-addypin-cyan bg-cyan-50'
                    : 'border-gray-200 hover:border-gray-300'
                }`}
                onClick={() => handlePinSelect(pin)}
                data-testid={`pin-item-${pin.shortcode}`}
              >
                <div className="flex items-center justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="font-semibold text-addypin-dark">
                        {pin.shortcode}
                      </span>
                      <span className="text-xs text-gray-500">
                        {getCountryFromCoords(Number(pin.latitude), Number(pin.longitude))}
                      </span>
                    </div>
                    <div className="text-xs text-gray-600 font-mono">
                      📍 {Number(pin.latitude).toFixed(4)}, {Number(pin.longitude).toFixed(4)}
                    </div>
                    <div className="text-xs text-gray-500 mt-1">
                      📅 {new Date(pin.createdAt).toLocaleDateString()}
                    </div>
                  </div>
                  <div className="ml-3 flex gap-1">
                    <Button
                      onClick={(e) => {
                        e.stopPropagation();
                        // Immediately select pin and start editing
                        handlePinSelect(pin);
                        setSelectedPin(pin);
                        if (onStartEditing) {
                          onStartEditing();
                        }
                      }}
                      size="sm"
                      variant="outline"
                      className="p-2"
                      data-testid={`button-edit-pin-${pin.shortcode}`}
                    >
                      <Edit className="w-3 h-3" />
                    </Button>
                    <Button
                      onClick={(e) => {
                        e.stopPropagation();
                        setShowDeleteConfirm(pin.shortcode);
                      }}
                      size="sm"
                      variant="outline"
                      className="p-2 text-red-600 hover:text-red-700 hover:bg-red-50"
                      data-testid={`button-delete-pin-${pin.shortcode}`}
                    >
                      <Trash2 className="w-3 h-3" />
                    </Button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {selectedPin && (
          <div className="mt-4 p-3 bg-cyan-50 border border-cyan-200 rounded-lg">
            <div className="text-sm font-medium text-cyan-800 mb-1">
              Selected: {selectedPin.shortcode}
            </div>
            <div className="text-xs text-cyan-700">
              Click "Edit" to modify coordinates on the map
            </div>
          </div>
        )}

        {/* Delete Confirmation Dialog */}
        <AlertDialog open={!!showDeleteConfirm} onOpenChange={(open) => !open && setShowDeleteConfirm(null)}>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>Delete addypin</AlertDialogTitle>
              <AlertDialogDescription>
                Are you sure you want to delete addypin {showDeleteConfirm}? It can't be undone and {showDeleteConfirm} addypin can be reused.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>Cancel</AlertDialogCancel>
              <AlertDialogAction
                onClick={() => showDeleteConfirm && deletePinMutation.mutate(showDeleteConfirm)}
                className="bg-red-600 hover:bg-red-700 text-white"
              >
                Delete addypin
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>
      </CardContent>
    </Card>
  );
}

client/src/hooks/use-mobile.tsx.content:
import * as React from "react"

const MOBILE_BREAKPOINT = 768

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined)

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener("change", onChange)
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    return () => mql.removeEventListener("change", onChange)
  }, [])

  return !!isMobile
}

client/src/hooks/use-toast.ts.content:
import * as React from "react"

import type {
  ToastActionElement,
  ToastProps,
} from "@/components/ui/toast"

const TOAST_LIMIT = 1
const TOAST_REMOVE_DELAY = 1000000

type ToasterToast = ToastProps & {
  id: string
  title?: React.ReactNode
  description?: React.ReactNode
  action?: ToastActionElement
}

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const

let count = 0

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER
  return count.toString()
}

type ActionType = typeof actionTypes

type Action =
  | {
      type: ActionType["ADD_TOAST"]
      toast: ToasterToast
    }
  | {
      type: ActionType["UPDATE_TOAST"]
      toast: Partial<ToasterToast>
    }
  | {
      type: ActionType["DISMISS_TOAST"]
      toastId?: ToasterToast["id"]
    }
  | {
      type: ActionType["REMOVE_TOAST"]
      toastId?: ToasterToast["id"]
    }

interface State {
  toasts: ToasterToast[]
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>()

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId)
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    })
  }, TOAST_REMOVE_DELAY)

  toastTimeouts.set(toastId, timeout)
}

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      }

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      }

    case "DISMISS_TOAST": {
      const { toastId } = action

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId)
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id)
        })
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t
        ),
      }
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        }
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      }
  }
}

const listeners: Array<(state: State) => void> = []

let memoryState: State = { toasts: [] }

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action)
  listeners.forEach((listener) => {
    listener(memoryState)
  })
}

type Toast = Omit<ToasterToast, "id">

function toast({ ...props }: Toast) {
  const id = genId()

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    })
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id })

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss()
      },
    },
  })

  return {
    id: id,
    dismiss,
    update,
  }
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState)

  React.useEffect(() => {
    listeners.push(setState)
    return () => {
      const index = listeners.indexOf(setState)
      if (index > -1) {
        listeners.splice(index, 1)
      }
    }
  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  }
}

export { useToast, toast }

client/src/hooks/useAuth.ts.content:
import { useUser, useClerk } from '@clerk/clerk-react';

export function useAuth() {
  try {
    const { user, isLoaded } = useUser();
    const { signOut } = useClerk();

    return {
      isAuthenticated: !!user,
      isLoading: !isLoaded,
      user,
      userId: user?.id || null,
      email: user?.primaryEmailAddress?.emailAddress || null,
      logout: () => signOut(),
    };
  } catch (error) {
    // If Clerk is not available, return default values
    console.warn('Clerk not available, using fallback auth state:', error);
    return {
      isAuthenticated: false,
      isLoading: false,
      user: null,
      userId: null,
      email: null,
      logout: () => console.warn('Authentication not available'),
    };
  }
}

