                        setEmail("");
                        setOtpCode("");
                        setLastOtpCode("");
                      }}
                      className="w-full"
                    >
                      Verify Different Email
                    </Button>
                  </div>
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}

