import { useState } from "react";
import { Link } from "wouter";
import MapSection from "@/components/MapSection";
import Sidebar from "@/components/Sidebar";
import Logo from "@/components/Logo";
import { EditModal } from "@/components/EditModal";
import { UserPinsList } from "@/components/UserPinsList";
import { QuickStats } from "@/components/QuickStats";
import { ContactForm } from "@/components/ContactForm";
import type { Pin } from "@shared/schema";

export default function Home() {
  const [coordinates, setCoordinates] = useState<{ lat: number; lng: number } | null>(null);
  const [generatedLink, setGeneratedLink] = useState<{ webLink: string; emailLink: string } | null>(null);
  const [showEditModal, setShowEditModal] = useState(false);
  const [editingPin, setEditingPin] = useState<Pin | undefined>();
  const [isEditing, setIsEditing] = useState(false);
  const [originalCoordinates, setOriginalCoordinates] = useState<{ lat: number; lng: number } | null>(null);
  const [userEmail, setUserEmail] = useState<string>("");
  const [otpCode, setOtpCode] = useState<string>("");

  return (
    <div className="min-h-screen bg-gray-50 font-inter">
      {/* Header */}
      <header className="bg-white shadow-sm border-b border-gray-200">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <Logo />
            <div className="flex items-center space-x-6">
              <nav className="hidden md:flex space-x-6">
                <Link href="/features" className="text-addypin-medium hover:text-addypin-dark transition-colors">
                  Features
                </Link>
                <a href="#" className="text-addypin-medium hover:text-addypin-dark transition-colors">
                  API
                </a>
                <a href="#contact" className="text-addypin-medium hover:text-addypin-dark transition-colors">
                  Help
                </a>
              </nav>

            </div>
            <button className="md:hidden text-addypin-medium" data-testid="mobile-menu">
              <i className="fas fa-bars text-xl"></i>
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
          <div className="lg:col-span-2">
            <MapSection 
              coordinates={coordinates}
              onCoordinatesChange={setCoordinates}
              generatedLink={generatedLink}
              editingPin={editingPin}
              isEditing={isEditing}
              userEmail={userEmail}
              otpCode={otpCode}
              onEditComplete={(newCoords) => {
                if (editingPin && newCoords) {
                  // Save the new coordinates
                  setCoordinates(newCoords);
                  setIsEditing(false);
                  setEditingPin(undefined);
                  // Clear the generated link to avoid confusion
                  setGeneratedLink(null);
                }
              }}
            />
          </div>
          <div className="space-y-4">
            <QuickStats />
            <Sidebar 
              coordinates={coordinates}
              generatedLink={generatedLink}
              onLinkGenerated={setGeneratedLink}
              isMapWidth={false}
            />
            <UserPinsList
              onPinSelect={(pin) => {
                // Reset editing state when selecting a new pin
                setIsEditing(false);
                setEditingPin(pin);
                setOriginalCoordinates({
                  lat: Number(pin.latitude),
                  lng: Number(pin.longitude)
                });
                setCoordinates({
                  lat: Number(pin.latitude),
                  lng: Number(pin.longitude)
                });
                // Clear any existing generated link
                setGeneratedLink(null);
              }}
              onStartEditing={() => {
                setIsEditing(true);
                // Force immediate UI update
                setCoordinates(prevCoords => prevCoords ? {...prevCoords} : prevCoords);
              }}
              onAuthChange={(email, otp, isAuth) => {
                setUserEmail(email);
                setOtpCode(otp);
              }}
            />
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-gray-200 mt-6">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-3">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <div className="col-span-1 md:col-span-2">
              <div className="mb-2">
                <Logo />
              </div>
              <p className="text-addypin-medium text-xs">
                The simplest way to share locations across all map apps. 
                Open source and privacy-focused.
              </p>
            </div>
            <div>
              <h3 className="font-semibold text-addypin-dark mb-2 text-sm">Resources</h3>
              <ul className="space-y-1 text-xs text-addypin-medium">
                <li><Link href="/features" className="hover:text-addypin-cyan transition-colors">Features</Link></li>
                <li><a href="#" className="hover:text-addypin-cyan transition-colors">API Documentation</a></li>
                <li><Link href="/versions" className="hover:text-addypin-cyan transition-colors" data-testid="link-version-history-footer">Version History</Link></li>
                <li><a href="#" className="hover:text-addypin-cyan transition-colors">Help Center</a></li>
              </ul>
            </div>
            <div>
              <h3 className="font-semibold text-addypin-dark mb-2 text-sm">Legal</h3>
              <ul className="space-y-1 text-xs text-addypin-medium">
                <li><a href="#" className="hover:text-addypin-cyan transition-colors">Privacy Policy</a></li>
                <li><a href="#" className="hover:text-addypin-cyan transition-colors">Terms of Service</a></li>
                <li><a href="#" className="hover:text-addypin-cyan transition-colors">Cookie Policy</a></li>
              </ul>
            </div>
          </div>
          <div className="border-t border-gray-200 mt-2 pt-2 flex justify-between items-center">
            <p className="text-xs text-addypin-medium flex items-center">
              © 2025 addypin
              <a 
                href="https://www.linkedin.com/company/10224951/admin/products/cairenes-solutions-addypin/"
                target="_blank"
                rel="noopener noreferrer"
                className="ml-3 text-addypin-medium hover:text-addypin-cyan transition-colors"
                data-testid="link-linkedin-home"
              >
                <i className="fab fa-linkedin text-sm"></i>
              </a>
            </p>
          </div>
        </div>
      </footer>

      <EditModal 
        isOpen={showEditModal} 
        onClose={() => setShowEditModal(false)}
        onPinSelect={(pin) => {
          setEditingPin(pin);
          setOriginalCoordinates({
            lat: Number(pin.latitude),
            lng: Number(pin.longitude)
          });
          setCoordinates({
            lat: Number(pin.latitude),
            lng: Number(pin.longitude)
          });
        }}
        onStartEditing={() => {
          setIsEditing(true);
        }}
      />
    </div>
  );
}

frontend/src/pages/RedirectPage.tsx.content:
import { useRoute } from "wouter";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useState } from "react";
import * as React from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent } from "@/components/ui/card";
import { Edit, Lock, Unlock, MapPin } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import Logo from "@/components/Logo";
import MapSection from "@/components/MapSection";
import { getCountryFromCoords } from "@shared/utils";

interface Pin {
  id: string;
  shortcode: string;
  latitude: string;
  longitude: string;
  createdAt: string;
  userEmail?: string;
  isActive: boolean;
  createdBy?: string;
  expiresAt?: string;
}

interface MapLinks {
  [key: string]: string;
}

export default function RedirectPage() {
  const [, params] = useRoute("/redirect/:shortcode");
  const shortcode = params?.shortcode;
  const [editMode, setEditMode] = useState(false);
  const [email, setEmail] = useState("");
  const [otpCode, setOtpCode] = useState("");
  const [editToken, setEditToken] = useState("");
  const [showOtpInput, setShowOtpInput] = useState(false);
  const [coordinates, setCoordinates] = useState<{ lat: number; lng: number } | null>(null);
  const { toast } = useToast();

  const { data: pin, isLoading, error } = useQuery({
    queryKey: ["/api/pins", shortcode],
    enabled: !!shortcode,
  });

  const { data: mapLinks } = useQuery({
    queryKey: ["/api/map-links", (pin as Pin)?.latitude, (pin as Pin)?.longitude],
    enabled: !!pin,
  });

  const typedPin = pin as Pin;
  const typedMapLinks = mapLinks as MapLinks;

  // Set coordinates when pin is loaded
  React.useEffect(() => {
    if (typedPin) {
      setCoordinates({
        lat: parseFloat(typedPin.latitude),
        lng: parseFloat(typedPin.longitude)
      });
    }
  }, [typedPin]);

  // OTP mutations
  const sendOtpMutation = useMutation({
    mutationFn: async (email: string) => {
      const response = await apiRequest("POST", "/api/otp/send", { email });
      return response.json();
    },
    onSuccess: () => {
      setShowOtpInput(true);
      toast({
        title: "OTP Sent",
        description: "Check your email for the verification code",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: error instanceof Error ? error.message : "Failed to send OTP",
        variant: "destructive",
      });
    },
  });

  const verifyOtpMutation = useMutation({
    mutationFn: async ({ email, code }: { email: string; code: string }) => {
      const response = await apiRequest("POST", "/api/otp/verify", { email, code });
      return response.json();
    },
    onSuccess: (data) => {
      setEditToken(data.editToken);
      setEditMode(true);
      toast({
        title: "Verified",
        description: "You can now edit pin coordinates by dragging the pin",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: error instanceof Error ? error.message : "Invalid OTP",
        variant: "destructive",
      });
    },
  });

  const updatePinMutation = useMutation({
    mutationFn: async (newCoords: { lat: number; lng: number }) => {
      const response = await apiRequest("PUT", `/api/pins/${shortcode}`, {
        latitude: newCoords.lat,
        longitude: newCoords.lng,
        editToken,
      });
      return response.json();
    },
    onSuccess: () => {
      toast({
        title: "Pin Updated",
        description: "Coordinates have been updated successfully",
      });
      setEditMode(false);
      setEditToken("");
      setShowOtpInput(false);
      setOtpCode("");
      setEmail("");
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: error instanceof Error ? error.message : "Failed to update pin",
        variant: "destructive",
      });
    },
  });

  const handleCoordinatesChange = (newCoords: { lat: number; lng: number }) => {
    setCoordinates(newCoords);
    if (editMode && editToken) {
      // Auto-update when in edit mode
      updatePinMutation.mutate(newCoords);
    }
  };

  if (!shortcode) {
    return (
      <div className="min-h-screen w-full flex items-center justify-center bg-gray-50">
        <Card className="w-full max-w-md mx-4">
          <CardContent className="pt-6">
            <div className="text-center">
              <Logo />
              <p className="mt-4 text-sm text-gray-600">Invalid shortcode</p>
            </div>
          </CardContent>
        </Card>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="min-h-screen w-full flex items-center justify-center bg-gray-50">
        <Card className="w-full max-w-md mx-4">
          <CardContent className="pt-6">
            <div className="text-center">
              <Logo />
              <div className="mt-4 flex justify-center">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-addypin-cyan"></div>
              </div>
              <p className="mt-4 text-sm text-gray-600">Loading location...</p>
            </div>
          </CardContent>
        </Card>
      </div>
    );
  }

  if (error || !typedPin) {
    return (
      <div className="min-h-screen bg-gray-50 font-inter">
        <div className="container mx-auto px-4 py-8 max-w-4xl">
          <div className="text-center mb-8">
            <Logo />
            <p className="mt-4 text-lg text-gray-600">
              Location not found. Please check the link and try again.
            </p>
          </div>
        </div>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="min-h-screen bg-gray-50 font-inter">
        <div className="container mx-auto px-4 py-8 max-w-4xl">
          <div className="text-center mb-8">
            <Logo />
            <div className="mt-4 flex justify-center">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-addypin-cyan"></div>
            </div>
            <p className="mt-4 text-lg text-gray-600">Loading location...</p>
          </div>
        </div>
      </div>
    );
  }

  const mapApps = [
    { name: "Google Maps", icon: "fab fa-google" },
    { name: "Apple Maps", icon: "fab fa-apple" },
    { name: "Waze", icon: "fas fa-route" },
    { name: "HERE WeGo", icon: "fas fa-map" },
    { name: "MapQuest", icon: "fas fa-compass" },
    { name: "Maps.me", icon: "fas fa-map-marked-alt" },
    { name: "OpenStreetMap", icon: "fas fa-globe" },
    { name: "Bing Maps", icon: "fab fa-microsoft" },
    { name: "TomTom", icon: "fas fa-car" },
    { name: "Citymapper", icon: "fas fa-subway" },
    { name: "OsmAnd", icon: "fas fa-location-arrow" },
    { name: "Sygic Maps", icon: "fas fa-road" },
    { name: "Badger Maps", icon: "fas fa-briefcase" },
  ];

  return (
    <div className="min-h-screen bg-gray-50 font-inter">
      <div className="container mx-auto px-4 py-8 max-w-4xl">
        {/* Header */}
        <div className="text-center mb-8">
          <Logo />
          <h1 className="text-2xl font-semibold text-addypin-dark mt-4">
            {typedPin.shortcode} - {getCountryFromCoords(parseFloat(typedPin.latitude), parseFloat(typedPin.longitude))}
          </h1>
          <p className="text-addypin-medium mt-2">
            {typedPin.latitude}, {typedPin.longitude}
          </p>
        </div>

        {/* Main Content */}
        <div className="flex flex-col lg:flex-row gap-8">
          {/* Map Section */}
          <div className="lg:w-2/3">
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
              <h2 className="text-xl font-semibold text-addypin-dark mb-4 flex items-center">
                <MapPin className="w-5 h-5 mr-2 text-addypin-cyan" />
                Pin Location
              </h2>
              {coordinates && (
                <div className="h-96 rounded-lg overflow-hidden">
                  <MapSection 
                    coordinates={coordinates}
                    onCoordinatesChange={handleCoordinatesChange}
                    generatedLink={null}
                  />
                </div>
              )}
              <p className="text-sm text-gray-600 mt-3">
                Coordinates: {typedPin.latitude}, {typedPin.longitude}
              </p>
              {typedPin.createdBy && (
                <p className="text-xs text-gray-500 mt-1">
                  Created by: {typedPin.createdBy}
                </p>
              )}
              {typedPin.expiresAt && (
                <p className="text-xs text-amber-600 mt-1">
                  Expires: {new Date(typedPin.expiresAt).toLocaleDateString()}
                </p>
              )}
            </div>
          </div>

          {/* Sidebar */}
          <div className="lg:w-1/3 space-y-6">
            {/* Edit Section */}
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
              <h3 className="text-lg font-semibold text-addypin-dark mb-4 flex items-center">
                <Edit className="w-5 h-5 mr-2 text-addypin-cyan" />
                Edit addypin
              </h3>

              {!editMode ? (
                <div className="space-y-4">
                  <p className="text-sm text-gray-600">
                    Verify your email to edit this addypin's coordinates.
                  </p>

                  <div>
                    <Label htmlFor="edit-email" className="block text-sm font-medium text-addypin-dark mb-2">
                      Email for verification
                    </Label>
                    <div className="flex space-x-2">
                      <Input
                        id="edit-email"
                        type="email"
                        placeholder="your@email.com"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        className="flex-1"
                        data-testid="input-edit-email"
                      />
                      <Button
                        onClick={() => sendOtpMutation.mutate(email)}
                        disabled={!email || sendOtpMutation.isPending}
                        className="bg-addypin-cyan hover:bg-cyan-600 text-white px-4"
                        data-testid="button-send-otp"
                      >
                        {sendOtpMutation.isPending ? "Sending..." : "Send OTP"}
                      </Button>
                    </div>
                  </div>

                  {showOtpInput && (
                    <div>
                      <Label htmlFor="otp-code" className="block text-sm font-medium text-addypin-dark mb-2">
                        Verification Code
                      </Label>
                      <div className="flex space-x-2">
                        <Input
                          id="otp-code"
                          type="text"
                          placeholder="123456"
                          value={otpCode}
                          onChange={(e) => setOtpCode(e.target.value)}
                          maxLength={6}
                          className="flex-1 font-mono"
                          data-testid="input-otp-code"
                        />
                        <Button
                          onClick={() => verifyOtpMutation.mutate({ email, code: otpCode })}
                          disabled={!otpCode || verifyOtpMutation.isPending}
                          className="bg-green-600 hover:bg-green-700 text-white px-4"
                          data-testid="button-verify-otp"
                        >
                          {verifyOtpMutation.isPending ? "Verifying..." : "Verify"}
                        </Button>
                      </div>
                    </div>
                  )}
                </div>
              ) : (
                <div className="p-3 bg-green-50 border border-green-200 rounded-lg">
                  <p className="text-sm text-green-700 flex items-center">
                    <Unlock className="w-4 h-4 mr-2" />
                    Edit mode active! Drag the pin to update coordinates.
                  </p>
                </div>
              )}
            </div>

            {/* Map Apps Section */}
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
              <h3 className="text-lg font-semibold text-addypin-dark mb-4">
                Choose Your Map App
              </h3>

              <div className="grid grid-cols-1 gap-3">
                {typedMapLinks && Object.entries(typedMapLinks).map(([appName, link]) => (
                  <Button
                    key={appName}
                    asChild
                    variant="outline"
                    className="h-14 flex items-center justify-start p-4 hover:bg-addypin-cyan hover:text-white hover:border-addypin-cyan transition-all duration-200"
                    data-testid={`link-${appName.toLowerCase().replace(/\s+/g, '-')}`}
                  >
                    <a
                      href={link}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="w-full flex items-center"
                      onClick={async () => {
                        // Track map app click analytics
                        if (coordinates) {
                          try {
                            await apiRequest("POST", "/api/analytics/map-click", {
                              appName: appName,
                              latitude: coordinates.lat,
                              longitude: coordinates.lng
                            });
                            console.log(`Tracked click for ${appName}`);
                          } catch (error) {
                            console.log("Analytics tracking failed:", error);
                          }
                        }
                      }}
                    >
                      <span className="font-medium">{appName}</span>
                    </a>
                  </Button>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

frontend/src/pages/VersionPage.tsx.content:
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Link } from "wouter";
import { ArrowLeft, Calendar, GitBranch, Users, Zap } from "lucide-react";

interface VersionEntry {
  version: string;
  date: string;
  type: "major" | "minor" | "patch";
  title: string;
  description: string;
  features: string[];
  improvements: string[];
  fixes: string[];
}

const versions: VersionEntry[] = [
  {
    version: "1.0.0",
    date: "2025-08-14",
    type: "major",
    title: "Initial Release",
    description: "addypin launches as a complete location sharing service with dual-format URLs and comprehensive analytics.",
    features: [
      "Interactive map with draggable pins using Leaflet.js",
      "6-character auto-generated shortcodes (ABC123 format)",
      "Dual format support: web links and email format",
      "13+ map app integrations including Google Maps, Apple Maps, Waze",
      "Real-time statistics dashboard",
      "Email integration with location sharing",
      "PostgreSQL database with analytics tracking"
    ],
    improvements: [
      "Responsive design optimized for all devices",
      "Clean, lightweight architecture",
      "Privacy-focused approach with no recent pins display"
    ],
    fixes: []
  }
];

export default function VersionPage() {
  const getTypeColor = (type: string) => {
    switch (type) {
      case "major": return "bg-red-100 text-red-800 border-red-200";
      case "minor": return "bg-blue-100 text-blue-800 border-blue-200";
      case "patch": return "bg-green-100 text-green-800 border-green-200";
      default: return "bg-gray-100 text-gray-800 border-gray-200";
    }
  };

  const getTypeIcon = (type: string) => {
    switch (type) {
      case "major": return <Zap className="w-4 h-4" />;
      case "minor": return <GitBranch className="w-4 h-4" />;
      case "patch": return <Users className="w-4 h-4" />;
      default: return <Calendar className="w-4 h-4" />;
    }
  };

  return (
    <div className="min-h-screen bg-addypin-light">
      <div className="container mx-auto px-4 py-6 max-w-4xl">
        {/* Header */}
        <div className="mb-6">
          <Link href="/">
            <Button variant="ghost" className="mb-3" data-testid="button-back-home">
              <ArrowLeft className="w-4 h-4 mr-2" />
              Back to Home
            </Button>
          </Link>

          <h1 className="text-2xl font-bold text-addypin-dark mb-2">Version History</h1>
          <p className="text-sm text-addypin-medium">
            Track the evolution of AddyPin with detailed release notes and feature updates.
          </p>
        </div>

        {/* Version Timeline */}
        <div className="space-y-4">
          {versions.map((version, index) => (
            <Card key={version.version} className="border-l-4 border-l-addypin-cyan" data-testid={`version-${version.version}`}>
              <CardHeader className="pb-3">
                <div className="flex items-center justify-between">
                  <div className="flex items-center space-x-2">
                    <Badge className={`${getTypeColor(version.type)} flex items-center space-x-1 text-xs`}>
                      {getTypeIcon(version.type)}
                      <span>{version.type}</span>
                    </Badge>
                    <CardTitle className="text-addypin-dark text-lg">
                      v{version.version} - {version.title}
                    </CardTitle>
                  </div>
                  <div className="flex items-center text-addypin-medium text-xs">
                    <Calendar className="w-3 h-3 mr-1" />
                    {version.date}
                  </div>
                </div>
                <CardDescription className="text-sm">{version.description}</CardDescription>
              </CardHeader>

              <CardContent className="pt-0">
                <div className="space-y-3">
                  {/* Features */}
                  {version.features.length > 0 && (
                    <div>
                      <h4 className="font-medium text-addypin-dark mb-1 flex items-center text-sm">
