import express, { type Express } from "express";
import fs from "fs";
import path from "path";

export function log(message: string, source = "express") {
  const formattedTime = new Date().toLocaleTimeString("en-US", {
    hour: "numeric",
    minute: "2-digit",
    second: "2-digit",
    hour12: true,
  });

  console.log(`${formattedTime} [${source}] ${message}`);
}

export function serveStatic(app: Express) {
  const distPath = path.resolve(import.meta.dirname, "..", "dist", "public");

  if (!fs.existsSync(distPath)) {
    throw new Error(
      `Could not find the build directory: ${distPath}, make sure to build the client first`,
    );
  }

  app.use(express.static(distPath));

  // fall through to index.html if the file doesn't exist
  app.use("*", (_req, res) => {
    res.sendFile(path.resolve(distPath, "index.html"));
  });
}

docs/root-files/DIRECT_PRODUCTION_FIX.md.content:
# Direct Production Fix - Stop CI/CD Loop

**Issue**: We've been fixing CI/CD workflows when the real problem is production API 404 errors.

**Root Problem**: The production server at https://addypin.com has:
- Backend API returning 404 for `/api/pins` and `/api/otp/send`
- Duplicate database exports causing backend crashes
- nginx not configured for React Router

**Direct Solution**: Fix production manually, bypass CI/CD for now.

## Manual Production Fix Commands

SSH into your VPS and run these commands:

```bash
# 1. Fix the duplicate database exports
cd /opt/addypin
nano server/db.ts
# Remove duplicate lines, keep only:
# - Single connectionConfig 
# - Single pool export
# - Single db export

# 2. Add production API environment to frontend
echo "VITE_API_BASE_URL=https://addypin.com" > frontend/.env.production

# 3. Update nginx configuration
cat > frontend/nginx.conf << 'EOF'
server {
    listen 80;
    server_name addypin.com www.addypin.com;
    root /usr/share/nginx/html;
    index index.html;

    location / {
        try_files $uri $uri/ /index.html;
    }

    location /api {
        proxy_pass http://backend:5000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
    }
}
EOF

# 4. Rebuild and restart containers
docker-compose down
docker-compose build --no-cache
docker-compose up -d

# 5. Test
curl https://addypin.com/api/health
curl -X POST https://addypin.com/api/pins -H "Content-Type: application/json" -d '{"test":true}'
```

**Expected Result**: Pin creation and editing will work immediately.

**CI/CD**: Fix later after production is working.

docs/root-files/NGINX_FIX_COMMANDS.md.content:
# Fix nginx Routing for Production API

Run these commands on your VPS:

```bash
# Check current nginx configuration
docker-compose exec frontend cat /etc/nginx/conf.d/default.conf

# Create proper nginx configuration
cat > frontend/nginx.conf << 'EOF'
server {
    listen 80;
    server_name addypin.com www.addypin.com;
    root /usr/share/nginx/html;
    index index.html;

    # API requests go to backend
    location /api/ {
        proxy_pass http://backend:5000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }

    # Frontend routes (React Router)
    location / {
        try_files $uri $uri/ /index.html;
    }
}
EOF

# Rebuild frontend container with new nginx config
docker-compose build --no-cache frontend
docker-compose restart frontend

# Test API routing
curl -X POST https://addypin.com/api/pins \
  -H "Content-Type: application/json" \
  -d '{"latitude":"52.5200","longitude":"13.4050"}'

# Test health endpoint
curl https://addypin.com/api/health
```

docs/root-files/VPS_DOCKER_FIX.md.content:
# VPS Docker Build Context Fix

**Problem**: The frontend Dockerfile is not copying nginx.conf because of build context issues.

**Solution**: Fix the build context by modifying how docker-compose builds the frontend.

Run on VPS:

```bash
cd /opt/addypin

# Check current docker-compose.yml frontend build context
grep -A 10 "frontend:" docker-compose.yml

# Fix the build by using direct nginx config injection
cat > fix-frontend-build.sh << 'EOF'
#!/bin/bash
# Create a custom Dockerfile that directly includes the nginx config

cat > frontend/Dockerfile << 'DOCKERFILE'
# Multi-stage build for React frontend
FROM node:20-alpine AS builder

WORKDIR /app
COPY package*.json ./
RUN npm ci --no-audit
COPY . .
RUN npm run build

# Production stage with Nginx
FROM nginx:alpine AS production

# Copy built files
COPY --from=builder /app/dist /usr/share/nginx/html

# Directly embed nginx configuration
RUN cat > /etc/nginx/conf.d/default.conf << 'NGINXCONF'
server {
    listen 80;
    server_name addypin.com www.addypin.com;
    root /usr/share/nginx/html;
    index index.html;

    location /api/ {
        proxy_pass http://backend:5000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }

    location / {
        try_files $uri $uri/ /index.html;
    }
}
NGINXCONF

EXPOSE 80
CMD ["nginx", "-g", "daemon off;"]
DOCKERFILE

# Rebuild with embedded config
docker-compose build --no-cache frontend
docker-compose up -d frontend
EOF

chmod +x fix-frontend-build.sh
./fix-frontend-build.sh

# Test
curl -X POST https://addypin.com/api/pins -H "Content-Type: application/json" -d '{"latitude":"52.5200","longitude":"13.4050"}'
```

docs/root-files/quick-fix-commands.md.content:
# Quick Fix: nginx Configuration for CentOS

## Check service status first:
```bash
systemctl status addypin.service
journalctl -u addypin.service -f --lines=20
```

## Fix nginx configuration (CentOS structure):
```bash
# Create nginx config directly in conf.d (CentOS standard)
sudo tee /etc/nginx/conf.d/addypin.conf > /dev/null << 'EOF'
server {
    listen 80;
    server_name addypin.com www.addypin.com;

    location / {
        proxy_pass http://localhost:3000;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_cache_bypass $http_upgrade;
    }
}
EOF

# Test and start nginx
sudo nginx -t
sudo systemctl start nginx
sudo systemctl enable nginx
```

## Test the complete deployment:
```bash
curl -I http://localhost:3000  # Direct app test
curl -I http://localhost       # nginx proxy test
```

